import React, { useState, useEffect } from "react";
import "./Department.css";

const STORAGE_KEY = "departments";

const DepartmentList = () => {
  const [departments, setDepartments] = useState([]);
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState(null);

  const [department, setDepartment] = useState({
    name: "",
    description: "",
  });

  /* ===========================
        LOAD FROM localStorage
  ============================ */
  useEffect(() => {
    const stored = JSON.parse(localStorage.getItem(STORAGE_KEY)) || [
      { id: 1, name: "IT", description: "Handles technical operations" },
      { id: 2, name: "HR", description: "Manages employees & HR operations" },
      { id: 3, name: "Finance", description: "Handles accounts & payroll" },
    ];

    setDepartments(stored);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(stored));
  }, []);

  /* ===========================
        SAVE HELPER
  ============================ */
  const saveToStorage = (data) => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
    setDepartments(data);
  };

  /* ===========================
        INPUT HANDLER
  ============================ */
  const handleChange = (e) => {
    setDepartment({ ...department, [e.target.name]: e.target.value });
  };

  /* ===========================
        ADD
  ============================ */
  const handleAdd = () => {
    setDepartment({ name: "", description: "" });
    setEditingId(null);
    setShowForm(true);
  };

  /* ===========================
        EDIT
  ============================ */
  const handleEdit = (dept) => {
    setDepartment({ name: dept.name, description: dept.description });
    setEditingId(dept.id);
    setShowForm(true);
  };

  /* ===========================
        SAVE (ADD / UPDATE)
  ============================ */
  const handleSubmit = (e) => {
    e.preventDefault();

    if (!department.name.trim()) {
      alert("Department Name is required");
      return;
    }

    let updated;

    if (editingId) {
      updated = departments.map((d) =>
        d.id === editingId
          ? { ...d, name: department.name, description: department.description }
          : d
      );
    } else {
      updated = [
        ...departments,
        {
          id: Date.now(),
          name: department.name,
          description: department.description,
        },
      ];
    }

    saveToStorage(updated);
    setShowForm(false);
  };

  /* ===========================
        DELETE
  ============================ */
  const handleDelete = (id) => {
    if (window.confirm("Are you sure to delete this department?")) {
      const updated = departments.filter((d) => d.id !== id);
      saveToStorage(updated);
    }
  };

  return (
    <div className="department-scope">


      <h2>Manage Departments</h2>

      <button className="add-btn" onClick={handleAdd}>
        Add New Department
      </button>

      {/* ===================== TABLE ===================== */}
      <div className="department-table-card">
        <table className="department-table">
          <thead>
            <tr>
              <th>S No</th>
              <th>Department Name</th>
              <th>Description</th>
              <th>Action</th>
            </tr>
          </thead>

          <tbody>
            {departments.map((dept, index) => (
              <tr key={dept.id}>
                <td>{index + 1}</td>
                <td>{dept.name}</td>
                <td>{dept.description}</td>
                <td>
                  <button className="edit-btn" onClick={() => handleEdit(dept)}>
                    Edit
                  </button>

                  <button
                    className="delete-btn"
                    onClick={() => handleDelete(dept.id)}
                  >
                    Delete
                  </button>
                </td>
              </tr>
            ))}

            {departments.length === 0 && (
              <tr>
                <td colSpan="4" style={{ textAlign: "center" }}>
                  No Departments Found
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {/* ===================== FORM CARD ===================== */}
      {showForm && (
        <div className="add-department-card">
          <h3>{editingId ? "Edit Department" : "Add New Department"}</h3>

          <form className="add-department-form" onSubmit={handleSubmit}>
            <div className="form-group">
              <label>Department Name</label>
              <input
                type="text"
                name="name"
                value={department.name}
                onChange={handleChange}
                placeholder="Enter department name"
                required
              />
            </div>

            <div className="form-group">
              <label>Description</label>
              <textarea
                name="description"
                value={department.description}
                onChange={handleChange}
                placeholder="Enter description"
              />
            </div>

            <div className="form-actions">
              <button type="submit" className="save-btn">
                {editingId ? "Update" : "Save"}
              </button>

              <button
                type="button"
                className="cancel-btn"
                onClick={() => setShowForm(false)}
              >
                Cancel
              </button>
            </div>
          </form>
        </div>
      )}
    </div>
  );
};

export default DepartmentList;
